 1→fn main() {
 2→    // Match libghostty's minimum deployment target to avoid linker warnings
 3→    println!("cargo:REDACTED.0");
 4→
 5→    tauri_build::build();
 6→
 7→    // Link libghostty and required macOS frameworks
 8→    let vendor_dir = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
 9→        .join("vendor")
10→        .join("ghostty");
11→
12→    let lib_path = vendor_dir.join("libghostty.a");
13→
14→    // Check that libghostty.a exists and isn't an LFS pointer
15→    if !lib_path.exists() {
16→        panic!(
17→            "\n\n\
18→            ERROR: libghostty.a not found at {path}\n\n\
19→            You need to either:\n\
20→            1. Set up Git LFS and re-pull:  git lfs install && git lfs pull\n\
21→            2. Download it manually:        ./src-tauri/vendor/ghostty/download.sh\n\
22→            3. Build from source:           see src-tauri/vendor/ghostty/BUILD.md\n\n",
23→            path = lib_path.display()
24→        );
25→    }
26→
27→    // An LFS pointer is a small text file (~130 bytes) starting with
28→    // "version https://git-lfs.github.com". A real .a archive starts with "!<arch>\n".
29→    if let Ok(header) = std::fs::read(&lib_path) {
30→        if header.starts_with(b"version https://git-lfs") {
31→            panic!(
32→                "\n\n\
33→                ERROR: libghostty.a is a Git LFS pointer, not the actual binary.\n\n\
34→                Run one of:\n\
35→                  git lfs pull\n\
36→                  ./src-tauri/vendor/ghostty/download.sh\n\n\
37→                See src-tauri/vendor/ghostty/BUILD.md for more details.\n\n"
38→            );
39→        }
40→    }
41→
42→    println!("cargo:rustc-link-search=native={}", vendor_dir.display());
43→    println!("cargo:rustc-link-lib=static=ghostty");
44→
45→    // C++ standard library required by glslang (shader compiler) in libghostty
46→    println!("cargo:rustc-link-lib=c++");
47→
48→    // macOS frameworks required by libghostty's Metal renderer
49→    println!("cargo:rustc-link-lib=framework=Metal");
50→    println!("cargo:rustc-link-lib=framework=MetalKit");
51→    println!("cargo:rustc-link-lib=framework=AppKit");
52→    println!("cargo:rustc-link-lib=framework=QuartzCore");
53→    println!("cargo:rustc-link-lib=framework=CoreGraphics");
54→    println!("cargo:rustc-link-lib=framework=IOSurface");
55→    println!("cargo:rustc-link-lib=framework=Foundation");
56→
57→    // Rerun if the static library changes
58→    println!("cargo:rerun-if-changed=vendor/ghostty/libghostty.a");
59→    println!("cargo:rerun-if-changed=vendor/ghostty/ghostty.h");
60→}
